import { useState, useEffect } from "react";
import API from "../../services/api";
import Navbar from "../../components/Navbar";
import Sidebar from "../../components/Sidebar";
import "../../pages/user/css/Dashboard.css";

function GlobalAdminDashboard() {
  const [stats, setStats] = useState(null);
  const [users, setUsers] = useState([]);

  useEffect(() => {
    const fetchGlobalStats = async () => {
      try {
        const statsRes = await API.get("/admin/dashboard-stats");
        setStats(statsRes.data);

        const usersRes = await API.get("/admin/all-users");
        setUsers(usersRes.data);
      } catch (err) {
        console.error("Failed to load admin dashboard", err);
      }
    };
    fetchGlobalStats();
  }, []);

  return (
    <div className="page-layout">
      <Sidebar />
      <div className="main-content">
        <Navbar title="Global Admin Dashboard" subtitle="Platform Overview" />
        <div className="content-area">
          {stats && (
            <div className="stats-grid">
              <div className="stat-card">
                <h3>Total Users 👥</h3>
                <div className="stat-value">{stats.total_users}</div>
              </div>
              <div className="stat-card">
                <h3>Total Companies 🏢</h3>
                <div className="stat-value">{stats.total_companies}</div>
              </div>
              <div className="stat-card">
                <h3>Total Jobs 💼</h3>
                <div className="stat-value">{stats.total_jobs}</div>
              </div>
              <div className="stat-card">
                <h3>Resumes Uploaded 📄</h3>
                <div className="stat-value">{stats.total_resumes}</div>
              </div>
            </div>
          )}

          <div style={{ marginTop: "2rem" }}>
            <h2 style={{ marginBottom: "1rem" }}>All Users</h2>
            <table className="jobs-table">
              <thead>
                <tr>
                  <th>Name</th>
                  <th>Email</th>
                  <th>Role</th>
                </tr>
              </thead>
              <tbody>
                {users.map((u) => (
                  <tr key={u.id}>
                    <td>{u.name}</td>
                    <td>{u.email}</td>
                    <td><span className={`status-badge ${u.role === 'Admin' ? 'delivered' : 'pending'}`}>{u.role}</span></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}

export default GlobalAdminDashboard;
